<?php

namespace Src\Containers\Billing\Bill\Actions;

use Src\Containers\Billing\Bill\DTO\BillSelfAppealSingleDTO;
use Src\Containers\Billing\BillSelfAppeal\Actions\UpdateBillSelfAppealAction;
use Src\Containers\User\Models\User;
use Src\Ship\Parents\Actions\Action;
use Src\Containers\Billing\Bill\Models\Bill;
use Src\Containers\Billing\Bill\DTO\BillSelfAppealDTO;
use Src\Containers\Billing\BillSelfAppeal\Actions\SyncBillSelfAppealAction;
use Src\Containers\Billing\BillSelfAppeal\DTO\BillSelfAppealDTO as BillModelLienDTO;
use Src\Containers\Billing\BillSelfAppeal\Models\BillSelfAppeal;

class SelfAppealBillAction extends Action
{
    public function __construct(
        private SyncBillSelfAppealAction $syncBillSelfAppealAction,
        private SendElectronicBillAction $sendElectronicBillAction,
        private UpdateBillSelfAppealAction $updateBillSelfAppealAction,
        private ResolveAdditionalBillDocumentIdsAction $resolveAdditionalBillDocumentIdsAction,
        private UpdateBillDocumentsFolderAction $updateBillDocumentsFolderAction,
    ) {
    }

    public function run(User $user, BillSelfAppealDTO $dto)
    {
        $bills = $this->processBill($user, $dto);

        return $bills;
    }

    private function processBill(User $user, BillSelfAppealDTO $dto)
    {
        $requestDto = $dto;
        $billCollection = collect($requestDto->bills);
        $billIds = $billCollection->pluck('bill_id')->toArray();

        $billDetails = $billCollection->keyBy('bill_id')->toArray();
        $bills = Bill::withoutGlobalScopes()->whereIn('id', $billIds)->get();

        foreach ($bills as $bill) {
            try {
                $requestedDocumentIds = $billDetails[$bill->id]->document_ids ?? [];
                $additionalDocumentIds = $this->resolveAdditionalBillDocumentIdsAction->run($bill, $requestedDocumentIds);

                $documents = collect($requestedDocumentIds)->map(function ($documentId) {
                    return ['id' => $documentId];
                })->toArray();

                $modelDto = new BillModelLienDTO([
                    'email' => is_array($requestDto->email) && count($requestDto->email) ? $requestDto->email[0] : $requestDto->email,
                    'documents' => $documents,
                    'resync_documents' => false,
                    'sent_date' => now()->format('Y-m-d'),
                    'response_date' => $requestDto->response_date,
                    'response_method' => $requestDto->response_method,
                    'response_type' => $requestDto->response_type,
                    'notes' => $requestDto->notes,
                ]);

                $this->syncBillSelfAppealAction->run($bill, $modelDto);

                $this->updateBillDocumentsFolderAction->runForDocumentIds($bill, $additionalDocumentIds);

                if ($modelDto->response_method == BillSelfAppeal::RESPONSE_METHOD_ELECTRONIC_APPEAL) {
                    $this->sendElectronicBillAction->run($bill, $user, false, true); // TODO: change to a new Action
                }
            } catch (\Exception $e) {
                continue;
            }
        }

        return $bills;
    }

    public function runSingle(User $user, BillSelfAppeal $billSelfAppeal, BillSelfAppealSingleDTO $dto)
    {
        $requestDto = $dto;
        $requestedDocumentIds = $requestDto->document_ids ?? [];
        $billSelfAppeal->loadMissing('bill');
        $additionalDocumentIds = $this->resolveAdditionalBillDocumentIdsAction->run($billSelfAppeal->bill, $requestedDocumentIds);

        $documents = collect($requestedDocumentIds)->map(function ($documentId) {
            return ['id' => $documentId];
        })->toArray();

        $modelDto = new BillModelLienDTO([
            'email' => is_array($requestDto->email) && count($requestDto->email) ? $requestDto->email[0] : $requestDto->email,
            'documents' => $documents,
            'resync_documents' => false,
            'sent_date' => now()->format('Y-m-d'),
            'response_date' => $requestDto->response_date,
            'response_method' => $requestDto->response_method,
            'response_type' => $requestDto->response_type,
            'notes' => $requestDto->notes,
        ]);

        $billSelfAppeal = $this->updateBillSelfAppealAction->run($billSelfAppeal, $modelDto);

        $this->updateBillDocumentsFolderAction->runForDocumentIds($billSelfAppeal->bill, $additionalDocumentIds);

        if ($modelDto->response_method == BillSelfAppeal::RESPONSE_METHOD_ELECTRONIC_APPEAL) {
            $this->sendElectronicBillAction->run($billSelfAppeal->bill, $user, false, true); // TODO: change to a new Action
        }

        return $billSelfAppeal;
    }
}


