<?php

namespace Src\Containers\Billing\Bill\Support;

use Src\Containers\Billing\Bill\Models\Bill;
use Src\Containers\InsuranceCompany\Models\InsuranceCompany;

final class BillPayerIdentifierResolver
{
    public static function resolve($insuranceRelation, ?string $billSpecialty = null): ?string
    {
        if (!$insuranceRelation) {
            return null;
        }

        $billSpecialty = Bill::normalizeBillSpecialty($billSpecialty);

        if ($billSpecialty === Bill::SPECIALTY_PHARMACY) {
            return self::resolveFromClearingHouseData(
                self::relationValue($insuranceRelation, 'pharmacy_clearing_house_type'),
                self::relationValue($insuranceRelation, 'pharmacy_clearing_house')
            );
        }

        return self::resolveFromClearingHouseData(
            self::relationValue($insuranceRelation, 'clearing_house_type'),
            self::relationValue($insuranceRelation, 'clearing_house'),
            self::relationValue($insuranceRelation, 'payer')
        );
    }

    public static function resolveFromInsuranceInfo(array $insuranceInfo, ?string $billSpecialty = null, ?string $fallbackPayer = null): ?string
    {
        $billSpecialty = Bill::normalizeBillSpecialty($billSpecialty);

        if ($billSpecialty === Bill::SPECIALTY_PHARMACY) {
            return self::resolveFromClearingHouseData(
                $insuranceInfo['pharmacy_clearing_house_type'] ?? null,
                $insuranceInfo['pharmacy_clearing_house'] ?? null
            );
        }

        return self::resolveFromClearingHouseData(
            $insuranceInfo['clearing_house_type'] ?? null,
            $insuranceInfo['clearing_house'] ?? null,
            $insuranceInfo['payer'] ?? $fallbackPayer
        );
    }

    public static function resolveClearingHouseType($insuranceRelation, ?string $billSpecialty = null): ?string
    {
        if (!$insuranceRelation) {
            return null;
        }

        $billSpecialty = Bill::normalizeBillSpecialty($billSpecialty);
        $clearingHouseType = $billSpecialty === Bill::SPECIALTY_PHARMACY
            ? self::relationValue($insuranceRelation, 'pharmacy_clearing_house_type')
            : self::relationValue($insuranceRelation, 'clearing_house_type');

        $clearingHouseType = self::nullableString($clearingHouseType);

        return $clearingHouseType === InsuranceCompany::CLEARING_HOUSE_TYPE_NONE
            ? null
            : $clearingHouseType;
    }

    public static function resolveFromClearingHouseData($clearingHouseType, $clearingHouse, $fallbackPayer = null): ?string
    {
        $clearingHouseType = self::nullableString($clearingHouseType);
        $clearingHouse = is_array($clearingHouse) ? $clearingHouse : [];

        return match ($clearingHouseType) {
            InsuranceCompany::CLEARING_HOUSE_TYPE_INFIN_EDI => self::nullableString($clearingHouse['jopari'] ?? null),
            InsuranceCompany::CLEARING_HOUSE_TYPE_CARISK_LC => self::nullableString($clearingHouse['carisk'] ?? null),
            InsuranceCompany::CLEARING_HOUSE_TYPE_AVAILITY => self::nullableString($clearingHouse['demension'] ?? null),
            InsuranceCompany::CLEARING_HOUSE_TYPE_OPTUM => self::nullableString($clearingHouse['vital'] ?? null),
            default => self::nullableString($fallbackPayer),
        };
    }

    private static function relationValue($insuranceRelation, string $key)
    {
        return $insuranceRelation->{$key} ?? null;
    }

    private static function nullableString($value): ?string
    {
        if ($value === null || $value === false) {
            return null;
        }

        $value = trim((string) $value);

        return $value !== '' ? $value : null;
    }
}


