--- app/src/Containers/Billing/BillItem/Actions/CreateBillItemAction.php (текущее содержимое) ---
<?php

namespace Src\Containers\Billing\BillItem\Actions;

use Illuminate\Support\Facades\Log;
use Src\Ship\Parents\Actions\Action;
use Src\Containers\CptCode\Models\CptCode;
use Src\Containers\Billing\Bill\Models\Bill;
use Src\Containers\Billing\BillItem\DTO\BillItemDTO;
use Src\Containers\Billing\BillItem\Events\BillItemCreated;
use Src\Containers\Billing\BillItem\Actions\GetRegionCoefficientBillItemAction;

class CreateBillItemAction extends Action
{
    public function __construct(
        private GetRegionCoefficientBillItemAction $getRegionCoefficientBillItemAction,
    ) {
    }

    public function run(Bill $bill, BillItemDTO $dto)
    {
        $createdBillItem = $bill->billItems()->create($dto->toArray());

        $createdBillItem->documents()->attach($dto->documents);

        $cptCodeIds = collect($dto->cpt_codes)->pluck('id')->filter()->unique()->values()->all();
        $cptCodesById = [];

        if (!empty($cptCodeIds)) {
            $cptCodesById = CptCode::withTrashed()
                ->with('serviceTypes')
                ->whereIn('id', $cptCodeIds)
                ->get()
                ->keyBy('id')
                ->all();
        }

        $incomingCptRows = [];

        foreach ($dto->cpt_codes as $cptCode) {
            $cptCodeData = $cptCodesById[$cptCode['id']] ?? null;

            if (!$cptCodeData) {
                Log::warning("CPT Code ID {$cptCode['id']} not found when creating BillItem for Bill ID {$bill->id}. Skipping this CPT Code.");
                continue;
            }
            $regionCoefficient = $this->getRegionCoefficientBillItemAction->run($bill, $cptCodeData);

            $data = [
                'doctor_id' => $cptCode['doctor_id'] ?? null,
                'region_coefficient' => $regionCoefficient,
                'units' => $cptCode['units'] ?? 0,
                'default_price' => $cptCode['default_price'] ?? 0,
                'rvu' => $this->resolveRvu($cptCode['rvu'] ?? null, $cptCodeData->rvu ?? null),
                'service_type_id' => $cptCode['service_type_id'] ?? null,
                'pointers' => json_encode($cptCode['pointers'] ?? []),
                'medical_modifier_name' => $cptCode['medical_modifier_name'] ?? null,
                'medical_modifier_id' => $cptCode['medical_modifier_id'] ?? null,
            ];

            $data = array_filter($data, fn($value) => $value !== null);

            $incomingCptRows[] = [
                'id' => $cptCode['id'],
                'pivot' => $data,
            ];
        }

        foreach ($incomingCptRows as $incomingCptRow) {
            $createdBillItem->cptCodes()->attach($incomingCptRow['id'], $incomingCptRow['pivot']);
        }

        $bill->userTouch();

        BillItemCreated::dispatch($createdBillItem);

        return $createdBillItem;
    }

    private function resolveRvu($value = null, $default = null)
    {
        if ($value !== null && !is_numeric($value)) {
            return $value;
        }

        if ($default !== null && !is_numeric($default)) {
            return $default;
        }

        if (is_numeric($value) && $value > 0) {
            return (float) number_format($value, 2, '.', '');
        }

        if ($default !== null && is_numeric($default) && $default > 0) {
            return (float) number_format($default, 2, '.', '');
        }

        return $value ?? $default;
    }
}


