<?php

namespace Src\Containers\Billing\BillItem\Actions;

use Src\Ship\Parents\Actions\Action;
use Src\Containers\Billing\BillItem\Models\BillItem;
use Src\Containers\Billing\BillItem\Events\BillItemDeleted;
use Src\Containers\Billing\BillItem\Events\BillItemUpdated;

class DeleteBillItemAction extends Action
{
    public function run(BillItem $billItem, $cptCode = null)
    {
        if ($cptCode) {
            $billItem->cptCodes()->detach($cptCode);

            if ($billItem->cptCodes()->count()) {
                $billItem->bill->userTouch();
                BillItemUpdated::dispatch($billItem);

                return $billItem;
            }
        }

        $billItem->cptCodes()->detach();

        $billItem->bill->userTouch();

        $billItem->delete();

        BillItemDeleted::dispatch($billItem);

        return $billItem;
    }
}


