<?php

namespace Src\Containers\Billing\BillItem\Actions;

use Illuminate\Support\Facades\Log;
use Src\Ship\Parents\Actions\Action;
use Src\Containers\CptCode\Models\CptCode;
use Src\Containers\Billing\Bill\Models\Bill;

class GetRegionCoefficientBillItemAction extends Action
{
    private const DEFAULT_REGION = 4;

    public function run(Bill $bill, CptCode $cptCode): float
    {
        if ($bill->isPharmacySpecialty()) {
            return 1.0;
        }

        $region = $bill->service_location_region ?? self::DEFAULT_REGION;
        $serviceType = $cptCode->relationLoaded('serviceTypes')
            ? $cptCode->serviceTypes->first()
            : $cptCode->serviceTypes()->first();

        if (!$serviceType) {
            Log::warning("CPT Code ID {$cptCode->id} does not have an associated Service Type.");
        }

        return $serviceType?->{"region_$region"} ?? 0.0;
    }
}

